import{_ as a,o as t,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Oppo Pre-Install","description":"","frontmatter":{"title":"Oppo Pre-Install","slug":"oppo-pre-install"},"headers":[],"relativePath":"developer-hub/oppo-pre-install.md","filePath":"developer-hub/oppo-pre-install.md"}'),i={name:"developer-hub/oppo-pre-install.md"};function r(p,e,l,s,h,c){return t(),n("div",null,[...e[0]||(e[0]=[o('<p><em>[Image: 2560]</em></p><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Branch partners with Oppo in order to support preload/pre-install attribution of your app&#39;s campaigns. Enabling support for this attribution will allow you to properly measure the full lifecycle of your customer before they make their first few conversions in the app.</p><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><p>In order to attribute pre-installs, you need to have completed the following:</p><ul><li>Implement the latest version of the Branch <a href="./android-basic-integration.html">Android SDK</a> into your app.</li></ul><h3 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h3><h3 id="_1-initiate-campaign-setup" tabindex="-1">1. Initiate Campaign Setup <a class="header-anchor" href="#_1-initiate-campaign-setup" aria-label="Permalink to &quot;1. Initiate Campaign Setup&quot;">​</a></h3><p>To initialize the campaign for Oppo, you will need to gather the following:</p><table tabindex="0"><thead><tr><th>What</th><th>Obtained from</th><th>Description</th></tr></thead><tbody><tr><td><code>$3p</code> value</td><td>Branch Account Manager</td><td>Contact your Branch account manager to set up the <code>$3p</code> value: <code>a_oppopai</code> for the campaign</td></tr><tr><td>utm_campaign</td><td>Customer</td><td>Set up the utm_campaign value : <code>a_oppopai</code> in the auto_Install XML file</td></tr><tr><td>package name</td><td>Customer</td><td>Contact the customer to provide the Application Id in their project</td></tr></tbody></table><h3 id="_2-oppo-needs-to-configure-the-package-name-and-utm-campaign-of-the-auto-install-parameters-app-in-the-xml-file-which-is-described-in-the-official-doc" tabindex="-1">2. <code>Oppo</code> needs to configure the <code>package name</code> and <code>utm_Campaign</code> of the Auto-Install parameters app in the XML file which is described in the official doc. <a class="header-anchor" href="#_2-oppo-needs-to-configure-the-package-name-and-utm-campaign-of-the-auto-install-parameters-app-in-the-xml-file-which-is-described-in-the-official-doc" aria-label="Permalink to &quot;2. `Oppo` needs to configure the `package name` and `utm_Campaign` of the Auto-Install parameters app in the XML file which is described in the official doc.&quot;">​</a></h3><p><em>[Image: 1751]</em></p><p>Auto-Install XML file</p><p><em>[Image: 1552]</em></p><p>Although utmMedium is set in the configuration file, the Google Play Install referrer API gets a fixed value &quot;preload&quot;.</p><h3 id="_3-set-the-ad-partner-in-the-oncreate-method-of-the-application-class-which-extends-the-android-application-class" tabindex="-1">3. Set the Ad Partner in the onCreate method of the application class which extends the Android Application class <a class="header-anchor" href="#_3-set-the-ad-partner-in-the-oncreate-method-of-the-application-class-which-extends-the-android-application-class" aria-label="Permalink to &quot;3. Set the Ad Partner in the onCreate method of the application class which extends the Android Application class&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@Override</span></span>\n<span class="line"><span>    public void onCreate() {</span></span>\n<span class="line"><span>        super.onCreate();</span></span>\n<span class="line"><span>       Branch.getInstance().setPreinstallPartner(&quot;a_oppopai&quot;);</span></span>\n<span class="line"><span>}</span></span></code></pre></div><h3 id="_4-enable-oppo-in-branch" tabindex="-1">4. Enable Oppo in Branch <a class="header-anchor" href="#_4-enable-oppo-in-branch" aria-label="Permalink to &quot;4. Enable Oppo in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads &gt; Partner Management</strong>, find/search for OppoPai. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_oppopai?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><h3 id="_5-view-data-in-branch" tabindex="-1">5. View Data in Branch <a class="header-anchor" href="#_5-view-data-in-branch" aria-label="Permalink to &quot;5. View Data in Branch&quot;">​</a></h3><p>As campaigns run, you will be able to measure the performance of the pre-install analytics directly on the Branch Dashboard.</p><p><em>[Image: 1544]</em></p>',22)])])}const m=a(i,[["render",r]]);export{u as __pageData,m as default};
